const CLIENT_ID_KEY = "bk_client_id";
const getClientId = () => {
  let id = localStorage.getItem(CLIENT_ID_KEY);
  if (!id) { id = "client-" + Math.random().toString(36).slice(2, 10); localStorage.setItem(CLIENT_ID_KEY, id); }
  return id;
};

