// ─── INTAKE → RETENTION MAPPING ──────────────────────────────────────────────
// Maps every field from BankruptcyIntake's useState into the retention sections.
// Fields imported from intake are flagged so the UI can show "✓ from intake" tags.
function mapIntakeToRetention(intake) {
  if (!intake) return { data: {}, importedKeys: new Set() };
  // BAN-27 Blocker 2: normalize across (a) old JSONB blob nested intake.form_data.*,
  // (b) old camelCase columns, and (c) new snake_case columns from intake_submissions.
  // After this call, the rest of this function can read camelCase off `intake` regardless
  // of which form wrote the row.
  intake = normalizeIntake(intake);
  const mapped = {};
  const imp = new Set(); // tracks which keys were populated from intake
  const tag = (...keys) => keys.forEach(k => imp.add(k));

  // ── Determine computed monthly gross from debtorSources array ──────────────
  const periodToMonthly = (amount, freq) => {
    const n = parseFloat(amount) || 0;
    const m = { Weekly: 52/12, "Bi-Weekly": 26/12, "Semi-Monthly": 2, Monthly: 1 };
    return n * (m[freq] || 0);
  };
  const srcGross = (src) =>
    src.sourceType === "employment"
      ? periodToMonthly(src.grossPerPeriod, src.payFrequency)
      : parseFloat(src.businessGrossIncome) || 0;
  const srcNet = (src) =>
    src.sourceType === "employment"
      ? periodToMonthly(src.netPerPeriod, src.payFrequency)
      : (parseFloat(src.businessGrossIncome) || 0) - (parseFloat(src.businessExpenses) || 0);

  const debtorMonthlyGross = (intake.debtorSources || []).reduce((s, src) => s + srcGross(src), 0);
  const spouseMonthlyGross = (intake.spouseSources || []).reduce((s, src) => s + srcGross(src), 0);

  // ── PETITION ────────────────────────────────────────────────────────────────
  // Infer marital status from filingType — joint and individual-nonfiling-spouse both mean Married
  const inferredMaritalStatus =
    intake.filingType === "joint" ? "Married" :
    intake.filingType === "individual-nonfiling-spouse" ? "Married" :
    ""; // "individual" could be Single, Divorced, Widowed — not determinable from intake alone

  mapped.petition = {
    // Identity (from intake)
    firstName:    intake.firstName,
    lastName:     intake.lastName,
    spouseFirst:  intake.spouseFirstName,
    spouseLast:   intake.spouseLastName,
    filingType:   intake.filingType,
    jointFiling:  intake.filingType === "joint" ? "Yes" : "No",
    chapter:      intake.chapter || "7",
    // Marital status — inferred from filingType when determinable
    maritalStatus: inferredMaritalStatus,
    // Residence (from intake — full address)
    addr1:        intake.streetAddress || "",
    zip:          intake.zipCode || "",
    state:        intake.state,
    county:       intake.county,
    city:         intake.city || "",
    addressYears: intake.addressYears,
    // Prior names (structured arrays from intake)
    priorNames:       Array.isArray(intake.priorNames) ? intake.priorNames : [],
    spousePriorNames: Array.isArray(intake.spousePriorNames) ? intake.spousePriorNames : [],
    // Prior addresses if < 2 years (from intake)
    priorAddr1:   intake.priorAddr1Street ? {
      street: intake.priorAddr1Street, city: intake.priorAddr1City,
      state:  intake.priorAddr1State,  from: intake.priorAddr1From, to: intake.priorAddr1To
    } : null,
    priorAddr2:   intake.priorAddr2Street ? {
      street: intake.priorAddr2Street, city: intake.priorAddr2City,
      state:  intake.priorAddr2State,  from: intake.priorAddr2From, to: intake.priorAddr2To
    } : null,
    priorAddr3:   intake.priorAddr3Street ? {
      street: intake.priorAddr3Street, city: intake.priorAddr3City,
      state:  intake.priorAddr3State,  from: intake.priorAddr3From, to: intake.priorAddr3To
    } : null,
    // Housing status — inferred from intake data
    housingFromIntake: intake.ownsRealEstate === "yes" ? "own"
      : (parseFloat(intake.expRentMortgage) > 0 ? "rent" : ""),
    housingStatus: intake.ownsRealEstate === "yes" ? "own"
      : (parseFloat(intake.expRentMortgage) > 0 ? "rent" : ""),
    // Mailing address — from intake when available
    mailingDifferent: intake.mailingAddressSameAsPrimary === "yes" ? "no"
      : intake.mailingAddressSameAsPrimary === "no" ? "yes" : "",
    mailingAddr1: "", mailingAddr2: "",
    mailingCity: "", mailingState: "", mailingZip: "",
    // Nature of debts — auto consumer unless business case indicated in intake
    isBusinessCase: intake.ownedBusiness === "yes",
    debtNature: intake.ownedBusiness !== "yes" ? "consumer" : "",
    // Dependents (from intake) — parse ages and relationships into per-dependent records
    numDependents: intake.numDependents,
    dependentAges: intake.dependentAges,
    dependents: (() => {
      const ages = String(intake.dependentAges || "").split(",").map(a => a.trim()).filter(Boolean);
      const rels = String(intake.dependentRelationships || "").split(",").map(r => r.trim()).filter(Boolean);
      const n = parseInt(intake.numDependents) || 0;
      return Array.from({ length: Math.max(n, ages.length) }, (_, i) => ({
        age: ages[i] || "",
        relationship: rels[i] || "",
        contributesToHousehold: "",
        monthlyContribution: "",
      }));
    })(),
    // SSN, DOB, and email from intake. SSN handled below — see BAN-27 Blocker 3.
    ssn:         "",
    ssnLastFour: "",
    ssnSpouse:   intake.ssnSpouse  || "",
    dob:         intake.dob        || "",
    dobSpouse:   intake.spouseDob  || "",
    email:       intake.email      || "",
    spouseEmail: intake.spouseEmail || "",
    streetAddress: "", zipCode: "", phone: "",
    spouseStreet: "", spouseZip: "", spousePhone: "",
  };

  // BAN-27 Blocker 3: SSN field labeling.
  // The new intake (ClientIntakeForm.tsx) collects only the last 4 digits (ssn_last4).
  // The portal still requires the full SSN — we must not prefill the SSN input with
  // a 4-digit value the user might submit as their full SSN. Cases:
  //   - intake provided ssnLastFour (or snake-case ssn_last4) → set ssnLastFour for hint
  //   - intake provided ssn that is exactly 4 digits → treat as last 4
  //   - intake provided ssn longer than 4 digits → treat as legacy full SSN
  const intakeSsnDigits      = String(intake.ssn         || "").replace(/\D/g, "");
  const intakeSsnLast4Digits = String(intake.ssnLastFour || "").replace(/\D/g, "");
  if (intakeSsnLast4Digits.length === 4) {
    mapped.petition.ssnLastFour = intakeSsnLast4Digits;
    tag("petition.ssnLastFour");
  } else if (intakeSsnDigits.length === 4) {
    mapped.petition.ssnLastFour = intakeSsnDigits;
    tag("petition.ssnLastFour");
  } else if (intakeSsnDigits.length > 4) {
    mapped.petition.ssn = intake.ssn;
    tag("petition.ssn");
  }
  if (intake.ssnSpouse) tag("petition.ssnSpouse");
  if (intake.dob)       tag("petition.dob");
  if (intake.spouseDob) tag("petition.dobSpouse");
  if (intake.email)     tag("petition.email");
  if (intake.spouseEmail) tag("petition.spouseEmail");
  if (intake.mailingAddressSameAsPrimary) tag("petition.mailingDifferent");
  tag("petition.firstName","petition.lastName","petition.spouseFirst","petition.spouseLast",
      "petition.filingType","petition.chapter","petition.state","petition.county",
      "petition.addr1","petition.zip","petition.addressYears","petition.city","petition.housingStatus",
      "petition.priorNames","petition.spousePriorNames","petition.numDependents","petition.dependentAges",
      "petition.jointFiling","petition.priorAddr1","petition.priorAddr2","petition.priorAddr3");
  if (intake.dependentRelationships) tag("petition.dependentRelationships");
  // Tag maritalStatus only if we could actually infer it from filingType
  if (inferredMaritalStatus) tag("petition.maritalStatus");

  // ── SCHEDULE A/B — REAL PROPERTY ─────────────────────────────────────────
  // zip and county are populated at render time from d.petition (confirmed on the petition page)
  if (intake.ownsRealEstate === "yes") {
    const props = [{
      addr:            intake.realPropAddress || "",
      city:            intake.city || "",
      state:           intake.state,
      zip:             intake.zip || "",
      county:          intake.county || "",
      description:     (() => {
        const t = (intake.realPropType || "").toLowerCase();
        if (t.includes("condo") || t.includes("co-op") || t.includes("cooperative")) return "Condominium or Cooperative";
        if (t.includes("duplex") || t.includes("multi") || t.includes("unit")) return "Duplex or Multi-Unit Building";
        if (t.includes("mobile") || t.includes("manufactured")) return "Manufactured or Mobile Home";
        if (t.includes("timeshare") || t.includes("time share") || t.includes("time-share")) return "Timeshare";
        if (t.includes("investment") || t.includes("rental")) return "Investment Property";
        // "primary residence", "single family", "house", blank, or anything else → Single-Family Home
        return "Single-Family Home";
      })(),
      interest:        "Fee Simple",
      value:           intake.realPropValue,
      debtorPct:       "100",
      purchaseDate:    intake.realPropPurchaseDate || "",
      purchaseDateConfirmed: false,
      // Mortgage — from intake
      mortgageBalance:  intake.mortgageBalance,
      mortgageCurrent:  intake.mortgageCurrent
        ? (intake.mortgageCurrent.toLowerCase() === "yes" ? "Yes" : "No")
        : "",
      mortgageCurrentConfirmed: false,
      mortgageArrears:  intake.mortgageArrears,
      monthlyPayment:   intake.expRentMortgage || "",
      mortgageStatementDate: "",
      // Translate intake T&I flag into the 4-option format
      mortgageIncludesTaxInsurance: (() => {
        const inc = intake.mortgageIncludesInsurance;
        const hasTax = parseFloat(intake.mortgageTaxAmount) > 0;
        const hasIns = parseFloat(intake.mortgageInsuranceAmount) > 0;
        if (inc === "yes") {
          if (hasTax && hasIns) return "both";
          if (hasTax && !hasIns) return "taxOnly";
          if (!hasTax && hasIns) return "insOnly";
          return "both";
        }
        return "neither";
      })(),
      lenderName:      intake.mortgageLenderName || "",
      lenderAcct:      "",
      lenderPhone:     "",
      otherInfo:            "",
      zillowVerifiedDate:   "",
      hasHOA:          intake.hasHOA || (parseFloat(intake.expHoa) > 0 ? "yes" : ""),
      hoaName:         intake.hoaName || "",
      hoaMonthlyDues:  intake.hoaMonthlyDues || intake.expHoa || "",
      hoaArrears:      intake.hoaArrears || "0",
      hoaBalanceConfirmed: false,
      hoaManagementContact: "",
      hasSecondLien:        "",
      secondLiens: [],
    }];
    if (intake.secondProperty === "yes") {
      props.push({
        addr:            intake.secondPropAddress || "",
        city:            "",
        state:           "",
        zip:             "",
        county:          "",
        description:     "Single-Family Home",
        interest:        "Fee Simple",
        value:           intake.secondPropValue,
        debtorPct:       "100",
        purchaseDate:    "",
        mortgageBalance: intake.secondMortgage,
        mortgageCurrent: "",
        mortgageArrears: "",
        monthlyPayment:  "",
        lenderName:           "",
        lenderAcct:           "",
        lenderPhone:          "",
        otherInfo:            "",
        zillowVerifiedDate:   "",
        hasHOA:               "",
        hoaName:              "",
        hoaMonthlyDues:       "",
        hoaArrears:           "",
        hoaManagementContact: "",
        hasSecondLien:        "",
        secondLiens: [],
      });
    }
    mapped.schedAB_re = { hasRE: "Yes", properties: props };
    tag("schedAB_re.hasRE","schedAB_re.properties");
  } else {
    mapped.schedAB_re = { hasRE: intake.ownsRealEstate === "no" ? "No" : "" };
    if (intake.ownsRealEstate === "no") tag("schedAB_re.hasRE");
  }

  // ── SCHEDULE A/B — FINANCIAL ASSETS ──────────────────────────────────────
  // Bank accounts (full array from intake)
  const bankAccts = (intake.bankAccounts || []).filter(a => a.bankName || a.balance).map(a => ({
    bankName: a.bankName, accountType: a.accountType, balance: a.balance,
    // NOT in intake:
    accountNumberLast4: "", branchState: "",
  }));
  // Retirement (full array from intake)
  const retAccts = intake.noRetirement ? [] : (intake.retirementAccounts || []).filter(a => a.accountType || a.balance).map(a => ({
    accountType: a.accountType, institution: a.institution,
    balance: a.balance, ownerName: a.ownerName || intake.firstName,
    // NOT in intake:
    accountNumberLast4: "",
  }));
  // Life insurance (from intake) — include yearsOwned if present
  const policies = intake.hasLifeInsurance === "yes" ? (intake.lifePolicies || []).map(p => ({
    policyType: p.policyType, faceValue: p.faceValue,
    cashValue: p.cashValue, beneficiary: p.beneficiary,
    yearsOwned: p.yearsOwned || "",
    insurerName: p.insurerName || "", policyNumber: p.policyNumber || "",
  })) : [];
  // Annuities (from intake) — normalize yearsHeld -> yearsOwned
  const annuities = intake.hasAnnuities === "yes" ? (intake.annuities || []).filter(a => a.annuityType || a.currentValue).map(a => ({
    annuityType: a.annuityType, currentValue: a.currentValue,
    yearsOwned: a.yearsOwned || a.yearsHeld || "",
    beneficiary: a.beneficiary, issuerName: a.issuerName || "",
  })) : [];
  // Investment accounts — seed stocks/crypto as named entries if present
  const investments = [];
  if (intake.hasStocks === "yes" && intake.stocksDesc) {
    investments.push({ institution: "Brokerage / Investment Account", description: intake.stocksDesc, value: intake.stocksValue, accountNumberLast4: "" });
  }

  mapped.schedAB_fin = {
    bankAccounts: bankAccts, retirement: retAccts,
    lifeInsurance: policies, annuities, investments,
    hasAnnuities: intake.hasAnnuities,
    hasStocks: intake.hasStocks, stocksValue: intake.stocksValue, stocksDesc: intake.stocksDesc,
    hasCrypto:  intake.hasCrypto,  cryptoValue: intake.cryptoValue,  cryptoDesc: intake.cryptoDesc,
    hasPendingClaims: intake.hasPendingClaims, pendingClaimsDesc: intake.pendingClaimsDesc, pendingClaimsValue: intake.pendingClaimsValue,
    hasMoneyOwed: intake.hasMoneyOwed, moneyOwedDesc: intake.moneyOwedDesc, moneyOwedAmt: intake.moneyOwedAmt,
  };
  tag("schedAB_fin.bankAccounts","schedAB_fin.retirement","schedAB_fin.lifeInsurance",
      "schedAB_fin.annuities","schedAB_fin.hasStocks","schedAB_fin.hasCrypto",
      "schedAB_fin.hasPendingClaims","schedAB_fin.hasMoneyOwed");

  // ── SCHEDULE A/B — PERSONAL PROPERTY ─────────────────────────────────────
  // Vehicles (full array from intake)
  const vehicles = (intake.vehicles || []).filter(v => v.type || v.year).map(v => ({
    type: normalizeVehicleType(v.type),
    year: v.year, make: v.make, model: v.model,
    value: v.value,
    hasLienAnswer: v.hasLoan === "yes" ? "Yes — I have a loan" : (v.hasLoan === "no" ? "No — owned free and clear" : ""),
    loanBalance: v.loanBalance,
    monthlyPayment: v.monthlyPayment,
    interestRate: v.interestRate || "",
    loanConfirmed: false,
    ownedBy: "", ownershipInterest: "Full / Sole Owner",
    purchaseDate: v.purchaseDate || "",
    paymentsCurrent: v.paymentsCurrent === "current" ? "Yes — current" : v.paymentsCurrent === "behind" ? "No — past due" : "",
    _intakePaymentStatus: v.paymentsCurrent || "",
    // NOT in intake — questionnaire collects:
    lenderName: "", lenderAcct: "", lienPerfectedAnswer: "", insiderLoan: "",
  }));
  // Firearms (from intake)
  const firearms = intake.hasFirearms === "yes" ? (intake.firearms || []).filter(f => f.description).map(f => ({
    description: f.description, serialKnown: f.serialKnown, value: f.value,
    // NOT in intake:
    serialNumber: "",
  })) : [];

  mapped.schedAB_phy = {
    vehicles,
    householdGoodsValue: intake.householdGoodsValue,
    electronicsValue: intake.electronicsValue,
    jewelryValue: intake.jewelryValue, toolsValue: intake.toolsValue,
    hasFirearms: intake.hasFirearms, firearms,
    hasCollectibles: intake.hasCollectibles, collectiblesValue: intake.collectiblesValue, collectiblesDesc: intake.collectiblesDesc,
    hasOtherPersonalProp: intake.hasOtherPersonalProp, otherPersonalPropValue: intake.otherPersonalPropValue, otherPersonalPropDesc: intake.otherPersonalPropDesc,
  };
  tag("schedAB_phy.vehicles","schedAB_phy.householdGoodsValue","schedAB_phy.electronicsValue",
      "schedAB_phy.jewelryValue","schedAB_phy.toolsValue","schedAB_phy.hasFirearms",
      "schedAB_phy.hasCollectibles","schedAB_phy.hasOtherPersonalProp");

  // ── SCHEDULE D — SECURED CREDITORS ───────────────────────────────────────
  // Only pre-fill creditor name, monthly payment, interest rate, and loan origination date.
  // Amount, collateral, and value are intentionally left blank — client must confirm from current statement.
  const securedCreditors = [];
  if (parseFloat(intake.mortgageBalance) > 0) {
    securedCreditors.push({
      name: "", addr1: "", city: "", state: intake.state, zip: "", acct: "",
      amount: "", collateral: "", collateralValue: "",
      monthlyPayment: intake.mortgageMonthlyPayment || "",
      apr: intake.mortgageRate || "",
      dateIncurred: intake.mortgageOriginationDate || "",
      lenderPhone: "", loanNumber: "", propertyAddr: intake.realPropAddress || "",
      _intakeRef: { mortgageBalance: intake.mortgageBalance, collateral: "Real Property — Primary Residence", collateralValue: intake.realPropValue || "" },
    });
    tag("schedD.mortgage");
  }
  // Vehicle loans from vehicles array
  (intake.vehicles || []).filter(v => v.hasLoan === "yes" && v.loanBalance).forEach((v, i) => {
    securedCreditors.push({
      name: v.lenderName || "", addr1: "", city: "", state: "", zip: "", acct: "",
      amount: "", collateral: "", collateralValue: "",
      monthlyPayment: v.loanPayment || "",
      apr: v.loanRate || "",
      dateIncurred: v.loanOriginationDate || "",
      lenderPhone: "", loanNumber: "",
      _intakeRef: { loanBalance: v.loanBalance, collateral: `${v.year} ${v.make} ${v.model || ""}`.trim(), collateralValue: v.value || "" },
    });
    tag(`schedD.vehicle${i}`);
  });
  if (securedCreditors.length) mapped.schedD = { creditors: securedCreditors };

  // ── SCHEDULE E/F — PRIORITY ──────────────────────────────────────────────
  const priCreds = [];
  if (parseFloat(intake.taxDebt) > 0) {
    priCreds.push({ name: "IRS / State Revenue", addr1: "", city: "", state: "", zip: "", acct: "", dateIncurred: "", amount: intake.taxDebt, consideration: "Income taxes", taxYears: "" });
    tag("schedEF_pri.tax");
  }
  if (parseFloat(intake.domesticSupportArrears) > 0) {
    priCreds.push({ name: "", addr1: "", city: "", state: "", zip: "", acct: "", dateIncurred: "", amount: intake.domesticSupportArrears, consideration: "Domestic support arrears", courtName: "", caseNumber: "" });
    tag("schedEF_pri.dso");
  }
  if (priCreds.length) mapped.schedEF_pri = { creditors: priCreds };

  // ── SCHEDULE E/F — NON-PRIORITY ──────────────────────────────────────────
  const npCreds = [];
  if (parseFloat(intake.creditCardDebt) > 0) {
    npCreds.push({ name: "", addr1: "", city: "", state: "", zip: "", acct: "", dateIncurred: "", amount: intake.creditCardDebt, consideration: "Credit card debt", lastPayment: "" });
    tag("schedEF_np.cc");
  }
  if (parseFloat(intake.medicalDebt) > 0) {
    npCreds.push({ name: "", addr1: "", city: "", state: "", zip: "", acct: "", dateIncurred: "", amount: intake.medicalDebt, consideration: "Medical bills", lastPayment: "" });
    tag("schedEF_np.med");
  }
  if (parseFloat(intake.studentLoanDebt) > 0) {
    npCreds.push({ name: "", addr1: "", city: "", state: "", zip: "", acct: "", dateIncurred: "", amount: intake.studentLoanDebt, consideration: "Student loans (generally non-dischargeable)", servicer: "", loanType: "" });
    tag("schedEF_np.sl");
  }
  if (parseFloat(intake.personalLoanDebt) > 0) {
    npCreds.push({ name: "", addr1: "", city: "", state: "", zip: "", acct: "", dateIncurred: "", amount: intake.personalLoanDebt, consideration: "Personal loan", lastPayment: "" });
    tag("schedEF_np.pl");
  }
  if (parseFloat(intake.judgmentDebt) > 0) {
    npCreds.push({ name: "", addr1: "", city: "", state: "", zip: "", acct: "", dateIncurred: "", amount: intake.judgmentDebt, consideration: "Judgment", courtName: "", caseNumber: "", judgmentDate: "" });
    tag("schedEF_np.judgment");
  }
  if (parseFloat(intake.otherUnsecured) > 0) {
    npCreds.push({ name: "", addr1: "", city: "", state: "", zip: "", acct: "", dateIncurred: "", amount: intake.otherUnsecured, consideration: "Other unsecured debt", lastPayment: "" });
    tag("schedEF_np.other");
  }
  if (npCreds.length) mapped.schedEF_np = { creditors: npCreds };

  // ── SCHEDULE I — INCOME ──────────────────────────────────────────────────
  // Map full income source arrays including all employer details
  const employmentSources = (intake.debtorSources || []).filter(s => s.sourceType === "employment").map(s => ({
    employerName: s.employerName, payFrequency: s.payFrequency,
    grossPerPeriod: s.grossPerPeriod, netPerPeriod: s.netPerPeriod,
    monthlyGross: srcGross(s).toFixed(2), monthlyNet: srcNet(s).toFixed(2),
    receiveBonus: s.receiveBonus, bonusGross: s.bonusGross,
    // NOT in intake — questionnaire collects:
    employerAddress: "", employerCity: "", employerState: "", employerZip: "",
    employerPhone: "", employerEIN: "", startDate: "", occupation: "",
  }));
  const selfEmploySources = (intake.debtorSources || []).filter(s => s.sourceType === "selfEmployed").map(s => ({
    businessName: s.businessName, businessType: s.businessType,
    monthlyGross: srcGross(s).toFixed(2),
    businessAddress: "", businessCity: "", businessState: "", businessZip: "", businessEIN: "",
  }));
  const spouseEmploySources = (intake.spouseSources || []).filter(s => s.sourceType === "employment").map(s => ({
    employerName: s.employerName, payFrequency: s.payFrequency,
    grossPerPeriod: s.grossPerPeriod, netPerPeriod: s.netPerPeriod,
    monthlyGross: srcGross(s).toFixed(2), monthlyNet: srcNet(s).toFixed(2),
    employerAddress: "", employerCity: "", employerState: "", employerZip: "",
    employerPhone: "", startDate: "", occupation: "",
  }));


  mapped.schedI = {
    debtorWorkStatus: intake.debtorWorkStatus,
    employmentSources, selfEmploySources,
    spouseWorkStatus: intake.spouseWorkStatus,
    spouseEmploySources,
    debtorMonthlyGross: debtorMonthlyGross.toFixed(2),
    spouseMonthlyGross: spouseMonthlyGross.toFixed(2),
    // Government & other income (all from intake)
    dSsRetirement: intake.dSsRetirement, dSsDisability: intake.dSsDisability,
    dVeterans: intake.dVeterans, dUnemployment: intake.dUnemployment,
    dWorkersComp: intake.dWorkersComp, dPension: intake.dPension, dPensionSource: intake.dPensionSource,
    dSnap: intake.dSnap, dCashAssist: intake.dCashAssist, dHousingAssist: intake.dHousingAssist,
    dOtherGov: intake.dOtherGov, dRental: intake.dRental, dAlimony: intake.dAlimony,
    dChildSupport: intake.dChildSupport, dFamilySupport: intake.dFamilySupport,
    dRoyalties: intake.dRoyalties, dInvestment: intake.dInvestment,
    dOtherIncome: intake.dOtherIncome, dOtherIncomeDesc: intake.dOtherIncomeDesc,
    avgMonthly6: intake.avgMonthly6,
  };
  tag("schedI.debtorWorkStatus","schedI.employmentSources","schedI.debtorMonthlyGross",
      "schedI.spouseMonthlyGross","schedI.dSsRetirement","schedI.dSsDisability",
      "schedI.dPension","schedI.dRental","schedI.dAlimony","schedI.avgMonthly6",
      "schedI.spouseWorkStatus","schedI.spouseEmploySources");

  // ── SCHEDULE J — EXPENSES ────────────────────────────────────────────────
  mapped.schedJ = {
    expRentMortgage: intake.expRentMortgage, expPropTax: intake.expPropTax, expHoa: intake.expHoa,
    expElectricGas: intake.expElectricGas, expWaterSewer: intake.expWaterSewer,
    expPhone: intake.expPhone, expInternet: intake.expInternet,
    expFood: intake.expFood, expHouseholdSupplies: intake.expHouseholdSupplies,
    expClothing: intake.expClothing, expPersonalCare: intake.expPersonalCare,
    expGasFuel: intake.expGasFuel, expCarMaintenance: intake.expCarMaintenance,
    expPublicTransit: intake.expPublicTransit,
    vehiclePayments: (intake.vehicles || []).filter(v => v.hasLoan === "yes").map(v => v.monthlyPayment),
    expMedical: intake.expMedical,
    expInsHealth: intake.expInsHealth, expInsLife: intake.expInsLife,
    expInsVehicle: intake.expInsVehicle, expInsHome: intake.expInsHome,
    expInsDisability: intake.expInsDisability, expInsOther: intake.expInsOther,
    expChildcare: intake.expChildcare, expChildEducation: intake.expChildEducation,
    expCharitable: intake.expCharitable, expRecreation: intake.expRecreation,
    expHomeMaintenance: intake.expHomeMaintenance, expAddlTaxes: intake.expAddlTaxes,
    expAlimonyPaid: intake.expAlimonyPaid, expSupportOthers: intake.expSupportOthers,
    expGovFines: intake.expGovFines, expOther: intake.expOther,
  };
  ["expRentMortgage","expPropTax","expHoa","expElectricGas","expWaterSewer","expPhone",
   "expInternet","expFood","expHouseholdSupplies","expClothing","expPersonalCare",
   "expGasFuel","expCarMaintenance","expPublicTransit","expMedical","expInsHealth",
   "expInsVehicle","expChildcare","expCharitable","expOther"].forEach(k => tag(`schedJ.${k}`));

  // ── SOFA 1 — INCOME & BUSINESS ────────────────────────────────────────────
  mapped.sofa1 = {
    grossPrior: String((parseFloat(intake.avgMonthly6) || 0) * 12),
    debtorWorkStatus: intake.debtorWorkStatus,
    ownedBusiness: intake.ownedBusiness, businessDetails: intake.businessDetails,
    // NOT in intake:
    priorYearGross: "", twoYearPriorGross: "",
  };
  tag("sofa1.grossPrior","sofa1.ownedBusiness");

  // ── SOFA 2 — TRANSFERS & PAYMENTS ────────────────────────────────────────
  mapped.sofa2 = {
    hasTransfers: intake.transferredProperty,
    transfers: intake.transferredProperty === "yes" ? (intake.transfers || []).map(t => ({
      description: t.description, recipient: t.recipient, amount: t.amount,
      date: t.date, relationship: t.relationship,
    })) : [],
    hasPreferential: intake.preferentialPayments,
    preferentialEntries: intake.preferentialPayments === "yes" ? (intake.preferentialEntries || []).map(p => ({
      creditor: p.creditor, amount: p.amount, date: p.date,
      relationship: p.relationship, type: p.type,
    })) : [],
    recentLuxury: intake.recentLuxury, luxuryDetails: intake.luxuryDetails,
    garnishment: intake.garnishment,
  };
  tag("sofa2.hasTransfers","sofa2.transfers","sofa2.hasPreferential",
      "sofa2.preferentialEntries","sofa2.recentLuxury","sofa2.garnishment");

  // ── SOFA 3 — LEGAL & PRIOR CASES ─────────────────────────────────────────
  mapped.sofa3 = {
    priorBkFiled: intake.priorBankruptcy,
    priorBankruptcies: intake.priorBankruptcy === "yes" ? (intake.priorBankruptcies || []).map(b => ({
      chapter: b.chapter, disposition: b.disposition, district: b.district,
      caseNo: b.caseNumber,
      dateFiled: b.yearFiled ? `${b.yearFiled}-01-01` : "",
    })) : [],
    hasLawsuits: intake.pendingLawsuits, lawsuitDetails: intake.lawsuitDetails,
    dsoObligation: intake.dsoObligation, dsoAmount: intake.dsoAmount,
    expectedRefund: intake.expectedRefund, refundAmount: intake.refundAmount,
    hasRepo: "No",
  };
  tag("sofa3.priorBkFiled","sofa3.priorBankruptcies","sofa3.hasLawsuits",
      "sofa3.dsoObligation","sofa3.expectedRefund");

  // ── SOFA 4 — ACCOUNTS & PROPERTY ────────────────────────────────────────
  mapped.sofa4 = {
    financialAccounts: (intake.bankAccounts || []).filter(a => a.bankName).map(a => ({
      institution: a.bankName, accountType: a.accountType,
      balance: a.balance, closedLastYear: "No",
      // NOT in intake:
      accountNumberLast4: "", closedDate: "",
    })),
  };
  tag("sofa4.financialAccounts");

  return { data: mapped, importedKeys: imp };
}


