// Given a district key and county name, return the correct division (or null)
function inferDivision(district, county) {
  const d = DISTRICT_DIVISIONS[district];
  if (!d || !county) return null;
  for (const [div, counties] of Object.entries(d.countyMap)) {
    if (counties.map(c => c.toLowerCase()).includes(county.toLowerCase())) return div;
  }
  return null;
}

// Given a county name, find the matching district and division across all known districts
function inferDistrictFromCounty(county) {
  if (!county) return null;
  for (const [district, info] of Object.entries(DISTRICT_DIVISIONS)) {
    for (const [div, counties] of Object.entries(info.countyMap)) {
      if (counties.map(c => c.toLowerCase()).includes(county.toLowerCase())) {
        return { district, division: div };
      }
    }
  }
  return null;
}

