        const districtName = pd.district || `${pd.state || "your state"} Bankruptcy Court`;
        const stateName = pd.state || "your state";
        const addressYears = pd.addressYears || "";
        const longEnough = addressYears === "2+ years" || addressYears === "6 months – 2 years";
