      "ownershipType": "Individual / Applicant | Joint | Authorized User | etc",
      "status": "exact status text e.g. Open, Current Account | Closed, Account Closed | Open, DISPUTE RESOLVED | Collection",
      "loanType": "exact loan type line e.g. Revolving, Credit Card | Installment, Automobile | Mortgage, Conventional Real Estate Mortgage | Credit Line, Credit Line Secured | Open, Agriculture | Revolving",
      "term": "term if shown e.g. 360 Months, 60 Months, N/A",
